const body = $('Webhook — Receber CV').first().json.body;
const resumeId = body.resume_id;
const callbackUrl = body.callback_url;
const cvText = (body.cv_text || '').slice(0, 8000);

const fields = [
  'score: número inteiro entre 0 e 100 representando a qualidade geral do CV',
  'skills: lista de competências técnicas e soft skills como array de strings',
  'summary: resumo profissional do candidato em 2-3 frases',
  'experience: experiência profissional estruturada em texto',
  'education: formação académica',
  'languages: idiomas encontrados no CV',
  'feedback: análise com pontos fortes e sugestões de melhoria'
];

const prompt = 'Analisa o seguinte currículo. Responde APENAS com um JSON válido contendo exactamente estes campos:\n' +
  fields.join('\n') +
  '\n\nCurrículo:\n' + cvText;

const requestBody = JSON.stringify({
  model: 'llama3.2',
  stream: false,
  format: 'json',
  prompt: prompt
});

return [{ json: { resume_id: resumeId, callback_url: callbackUrl, requestBody } }];

const ollamaResp = $input.first().json;
const metadata = $('Construir Prompt CV').first().json;

let analysis = {};
try {
  const raw = ollamaResp.response || ollamaResp.text || '{}';
  analysis = JSON.parse(raw);
} catch(e) {
  analysis = {};
}

const score = Math.min(100, Math.max(0, parseFloat(analysis.score) || 50));
const skills = Array.isArray(analysis.skills)
  ? analysis.skills.join(', ')
  : String(analysis.skills || 'Não identificadas').trim();
const summary = String(analysis.summary || 'Resumo não disponível').trim();
const experience = String(analysis.experience || 'Não especificada').trim();
const education = String(analysis.education || 'Não especificada').trim();
const languages = String(analysis.languages || 'Não identificados').trim();
const feedback = String(analysis.feedback || 'Análise concluída.').trim();

const requestBody = JSON.stringify({
  score, skills, summary, experience, education, languages, feedback
});

return [{
  json: {
    callback_url: metadata.callback_url,
    resume_id: metadata.resume_id,
    requestBody
  }
}];
